const useAllUsers = () => {
  return useQuery({
    queryKey: ["admin-all-users"],
    staleTime: 3e4,
    queryFn: async () => {
      const { data: profiles, error: pErr } = await supabase.from("profiles").select("*, tenants(id, business_name, business_vertical)").order("created_at", { ascending: false }).limit(500);
      if (pErr) throw pErr;
      const { data: members, error: mErr } = await supabase.from("tenant_memberships").select("*, tenants(id, business_name, business_vertical)");
      if (mErr) throw mErr;
      const memberAssociations = (members || []).map((m) => ({
        ...m,
        is_membership: true,
        // Since memberships don't have full_name, we rely on the grouping logic 
        // to find a matching profiles row with the same auth_user_id.
        full_name: m.full_name || null
      }));
      return [...profiles, ...memberAssociations];
    }
  });
};
