function useSiteConfig() {
  return useQuery({
    queryKey: ["site_config"],
    queryFn: async () => {
      const { data, error } = await supabase.from("site_config").select("key, value");
      if (error) throw error;
      return Object.fromEntries(data.map((r) => [r.key, r.value]));
    },
    staleTime: 1e3 * 60 * 10
  });
}
